import{_ as i,o as s,c as t,ae as a}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"GitHub Configuration Files for Branch Help Center","description":"","frontmatter":{},"headers":[],"relativePath":"README.md","filePath":"README.md"}'),n={name:"README.md"};function o(l,e,r,d,p,h){return s(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="github-configuration-files-for-branch-help-center" tabindex="-1">GitHub Configuration Files for Branch Help Center <a class="header-anchor" href="#github-configuration-files-for-branch-help-center" aria-label="Permalink to &quot;GitHub Configuration Files for Branch Help Center&quot;">​</a></h1><p>These files go in the root of your <code>branch-help-center</code> repo. Copy the entire <code>.github/</code> folder as-is.</p><h2 id="what-s-included" tabindex="-1">What&#39;s included <a class="header-anchor" href="#what-s-included" aria-label="Permalink to &quot;What&#39;s included&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.github/</span></span>
<span class="line"><span>├── workflows/</span></span>
<span class="line"><span>│   ├── build.yml              # Validates every PR builds successfully</span></span>
<span class="line"><span>│   └── deploy-preview.yml     # Deploys a preview URL for every PR</span></span>
<span class="line"><span>└── ISSUE_TEMPLATE/</span></span>
<span class="line"><span>    └── suggest-edit.yml       # &quot;Suggest an edit&quot; form for anonymous users</span></span></code></pre></div><h2 id="setup-steps" tabindex="-1">Setup steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup steps&quot;">​</a></h2><h3 id="_1-build-validation-build-yml-—-works-immediately" tabindex="-1">1. Build validation (build.yml) — works immediately <a class="header-anchor" href="#_1-build-validation-build-yml-—-works-immediately" aria-label="Permalink to &quot;1. Build validation (build.yml) — works immediately&quot;">​</a></h3><p>No setup needed. Once this file is in the repo, every pull request will automatically trigger a build. If the build fails (broken frontmatter, missing images, syntax errors), the PR gets a red X.</p><p>Your Writer will see this in the PR:</p><ul><li>✅ Green check = safe to merge</li><li>❌ Red X = something broke, click &quot;Details&quot; to see what</li></ul><h3 id="_2-preview-deploys-deploy-preview-yml-—-choose-one-option" tabindex="-1">2. Preview deploys (deploy-preview.yml) — choose one option <a class="header-anchor" href="#_2-preview-deploys-deploy-preview-yml-—-choose-one-option" aria-label="Permalink to &quot;2. Preview deploys (deploy-preview.yml) — choose one option&quot;">​</a></h3><p><strong>Option A: Use Vercel</strong></p><p>Delete <code>deploy-preview.yml</code> entirely. Instead:</p><ol><li>Go to <a href="https://vercel.com/new" target="_blank" rel="noreferrer">https://vercel.com/new</a></li><li>Import your GitHub repo</li><li>Framework preset: &quot;VitePress&quot; (or &quot;Other&quot; → build command: <code>npm run docs:build</code>, output: <code>docs/.vitepress/dist</code>)</li><li>Deploy</li></ol><p>That&#39;s it. Vercel automatically creates a preview URL for every PR and posts it as a comment. No secrets, no workflow file needed.</p><h3 id="_3-suggest-an-edit-template-suggest-edit-yml-—-works-immediately" tabindex="-1">3. Suggest-an-edit template (suggest-edit.yml) — works immediately <a class="header-anchor" href="#_3-suggest-an-edit-template-suggest-edit-yml-—-works-immediately" aria-label="Permalink to &quot;3. Suggest-an-edit template (suggest-edit.yml) — works immediately&quot;">​</a></h3><p>No setup needed. The template is available as soon as it&#39;s in the repo.</p><p>To link to it from your docs, add this to your VitePress config (see the &quot;Suggest an edit&quot; section in the migration plan for the full implementation).</p><h3 id="_4-vitepress-dead-link-detection-—-add-to-your-config" tabindex="-1">4. VitePress dead link detection — add to your config <a class="header-anchor" href="#_4-vitepress-dead-link-detection-—-add-to-your-config" aria-label="Permalink to &quot;4. VitePress dead link detection — add to your config&quot;">​</a></h3><p>VitePress can catch broken internal links at build time. Add this to your <code>.vitepress/config.mts</code>:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> default</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> defineConfig</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Fail the build if there are dead internal links.</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Start with &#39;warn&#39; during migration (lots of links will be broken),</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // switch to &#39;error&#39; once all content is migrated (Sprint 5+).</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ignoreDeadLinks: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// set to true or &#39;localhostLinks&#39; during early migration</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div><p>You&#39;ll probably want to set <code>ignoreDeadLinks: true</code> so broken cross-references don&#39;t block every PR. Once all content is migrated, flip it to <code>false</code> so broken links fail the build.</p>`,21)])])}const m=i(n,[["render",o]]);export{u as __pageData,m as default};
